export class LookupCache {
  private readonly entries = new Map<string, string>();

  constructor(private readonly fetcher: (key: string) => string) {}

  // `key` is derived from user input and effectively unbounded in cardinality.
  get(key: string): string {
    let value = this.entries.get(key);
    if (value === undefined) {
      value = this.fetcher(key);
      this.entries.set(key, value);
    }
    return value;
  }
}
